oxy_webhelp_navlinks = {"azure_stack_hci_overview-d30753e25355":{"topics":[{"title":"Azure Local management","shortdesc":"<p class=\"shortdesc\">Azure Local (Azure Stack HCI) is a hyperconverged clustering solution that uses         validated hardware to run virtualized workloads on-premises. Adding Azure Local to <span class=\"ph\">RSC<\/span> recognizes it as a Hyper-V cluster and discovers these virtualized         workloads as Hyper-V virtual machines. You can utilize Rubrik Hyper-V management         capabilities to manage Azure Local workloads.<\/p>","href":"saas\/hyper_v\/azure_stack_hci_management.html","attributes":{"data-id":"azure_stack_hci_management"},"menu":{"hasChildren":false},"tocID":"azure_stack_hci_management-d30753e25369","topics":[]},{"title":"Azure Local limitations","shortdesc":"<p class=\"shortdesc\">Recovering virtual machines to an Azure Local (Azure Stack HCI) has certain         limitations, but these limitations have workarounds.<\/p>","href":"saas\/hyper_v\/azure_stack_hci_limitations.html","attributes":{"data-id":"azure_stack_hci_limitations"},"menu":{"hasChildren":false},"tocID":"azure_stack_hci_limitations-d30753e25383","topics":[]},{"title":"RBS on Azure Local with WDAC enabled","shortdesc":"<p class=\"shortdesc\">Azure Local systems with Windows Defender Application Control enabled can run any         application enabled by the active policies. To install Rubrik Backup Service, you must first         deploy and activate the Windows Defender Application Control supplemental policy for Rubrik,         and then install the MSI package.<\/p>","href":"saas\/hyper_v\/rbs_azure_local_wdac_enabled.html","attributes":{"data-id":"rbs_azure_local_wdac_enabled"},"menu":{"hasChildren":false},"tocID":"rbs_azure_local_wdac_enabled-d30753e25394","next":"rbs_azure_local_wdac_enabled-d30753e25394"}]}};